INSERT INTO `content` VALUES (1,1,2,NULL,'2020-04-29 13:19:25','2020-09-17 14:36:18','c9d05a3f-c513-4c1e-b8a7-e55c4da5ff62',NULL,NULL,NULL,NULL,NULL,NULL),(3,2,2,'Homepage','2020-04-30 10:21:39','2025-10-08 15:56:58','499c34cd-36bd-441b-9fd6-90c7bb2fa8cf','<p>At <strong>Panda Engineering</strong>, we are specialists in <strong>precision engineering and power transmission solutions</strong>. From <strong>high-quality fabrication and sheet metal work</strong> to <strong>welding, CNC machining</strong>, and <strong>transmission component supply</strong>, our Bradford-based team delivers exceptional workmanship across <strong>West Yorkshire and the UK</strong>.</p>\n<p>We <strong>supply both manufactured and proprietary power transmission components</strong>, including <strong>shafts, couplings, gears, and bearing housings</strong>, alongside our comprehensive <strong>CNC machining and fabrication services</strong>. With advanced in-house capabilities and trusted supply partnerships, we ensure every component meets the highest standards of <strong>quality, accuracy, and performance</strong>.</p>\n<p>Serving a wide range of <strong>commercial, industrial, and maintenance sectors</strong>, <strong>Panda Engineering</strong> provides complete engineering solutions — from <strong>one-off prototypes</strong> to <strong>high-volume production</strong>. As one of <strong>Bradford’s leading precision engineering companies</strong>, we’re dedicated to delivering <strong>fast turnaround times, dependable quality, and exceptional customer service</strong>.</p>\n<p>&#x1f449; <strong>Contact us today</strong> at <strong><a>info@panda-engineering.co.uk</a></strong> or call <strong>01274 744 887</strong> to discuss your project or request a free quotation — and discover how <strong>Panda Engineering</strong> can keep your business moving with <strong>precision, reliability, and expertise.</strong></p>',':light_bulb: Discover more by clicking the images below :panda_face:',NULL,NULL,NULL,NULL),(9,5,2,'Hero','2020-04-30 10:23:14','2020-05-03 12:58:22','59586c22-26d7-4c89-8de7-4cb978e7a6e7',NULL,NULL,NULL,NULL,NULL,NULL),(15,11,2,'Homepage','2020-04-30 10:25:09','2020-04-30 10:25:09','11b1fa34-44e2-4c8a-99c8-aeeadbe6de17','<p>Our USP is our collective commercial, operational and financial (ICAEW) experience, practised and executed as cross functional leaders within live manufacturing and operational environments. Based in Yorkshire, we support a national and international customer base.</p>\n<p>Our customised services include pre-investment due diligence and post-deal monitoring, to highlight the true risk and potential of manufacturers to private equity and funding partners.<br /></p>\n<p>We take pride in our user-friendly, adaptable approach. As hands-on leaders we provide genuine one-stop support from boardroom to shop floor for manufacturing industry leaders and their funding partners.<br /></p>\n<p>We maximise throughput, cash flow and profitability by optimising the factors of production (land, labour, capital and enterprise).<br /></p>\n<p>The \"kadops way” promotes sustainable leadership, execution and reflection to aid business growth. Click on the images below or visit our case studies to find out more.</p>',NULL,NULL,NULL,NULL,NULL),(23,16,2,'Kadops triangle','2020-04-30 10:41:27','2020-05-03 12:57:42','9930ec69-3ee0-44ee-96d4-7b9279f4b09d',NULL,NULL,NULL,NULL,NULL,NULL),(25,17,2,'Sales','2020-04-30 10:41:38','2020-05-03 12:57:54','06e55944-ed06-4be4-a405-9603214728cb',NULL,NULL,NULL,NULL,NULL,NULL),(27,18,2,'Business turnaround','2020-04-30 10:43:10','2020-05-03 12:58:05','9a705c94-9a4c-4b30-a9b5-b9818e33795c',NULL,NULL,NULL,NULL,NULL,NULL),(29,19,2,'Brainstorm2','2020-04-30 10:44:34','2020-05-03 12:58:04','0edd161f-6a3d-4158-a46f-8609853e69ee',NULL,NULL,NULL,NULL,NULL,NULL),(33,29,2,'Operations','2020-04-30 10:52:41','2020-05-03 12:57:49','dceb5239-bd42-4dc1-aa07-d07f1cc7a997',NULL,NULL,NULL,NULL,NULL,NULL),(35,30,2,'Finance','2020-04-