e,\"ogImageTransformMode\":\"crop\",\"ogImageDescriptionSource\":\"\",\"ogImageDescriptionField\":\"\"}}'),(923,1783,2,'Fabrication & Sheet Metal Services','2022-07-05 15:15:28','2022-07-05 15:15:28','701d4e22-6a04-478c-8534-0a673cb5158a',NULL,NULL,'<p>Panda Engineering has many years of experience in fabrication services, steel fabrication and sheet metalwork. From your initial fabrication design concept right through to delivery of the finished product, we have the skills and experience to successfully complete the job and deliver within your timescale and budget. Seeking bespoke fabrications and sheet metalwork services? Contact Panda Engineering today.</p>',NULL,NULL,'{\"bundleVersion\":\"1.0.22\",\"sourceBundleType\":\"field\",\"sourceId\":null,\"sourceName\":null,\"sourceHandle\":null,\"sourceType\":\"field\",\"typeId\":null,\"sourceTemplate\":\"\",\"sourceSiteId\":null,\"sourceAltSiteSettings\":[],\"sourceDateUpdated\":\"2022-04-14T10:51:21+01:00\",\"metaGlobalVars\":{\"language\":null,\"mainEntityOfPage\":\"\",\"seoTitle\":\"Panda Engineering | Fabrication & Metalwork Services\",\"siteNamePosition\":\"\",\"seoDescription\":\"At Panda Engineering, we offer sheet metalwork, bespoke fabrication and engineering services across West Yorkshire and Bradford. Contact our team today.\",\"seoKeywords\":\"\",\"seoImage\":\"\",\"seoImageWidth\":\"\",\"seoImageHeight\":\"\",\"seoImageDescription\":\"\",\"canonicalUrl\":\"\",\"robots\":\"\",\"ogType\":\"\",\"ogTitle\":\"\",\"ogSiteNamePosition\":\"\",\"ogDescription\":\"\",\"ogImage\":\"\",\"ogImageWidth\":\"\",\"ogImageHeight\":\"\",\"ogImageDescription\":\"\",\"twitterCard\":\"\",\"twitterCreator\":\"\",\"twitterTitle\":\"\",\"twitterSiteNamePosition\":\"\",\"twitterDescription\":\"\",\"twitterImage\":\"\",\"twitterImageWidth\":\"\",\"twitterImageHeight\":\"\",\"twitterImageDescription\":\"\",\"inherited\":{\"seoKeywords\":true,\"seoImage\":true},\"overrides\":{\"seoTitle\":true,\"seoDescription\":true}},\"metaSiteVars\