INSERT INTO `matrixcontent_contentbuilder` VALUES (7,954,2,'2020-06-10 13:43:15','2020-09-25 12:20:56','dc04865c-b1cf-4ddf-ba51-bece59b61fcf',NULL,'<p>Cracked alloy wheels are becoming an increasingly common problem due to poor road conditions. </p><p>We can repair cracks, stress fractures or kerb damage whilst maintaining the wheel strength and integrity.</p>\n\n<p>The first step of the repair process is to grind both sides of the crack (to remove any contamination therefore giving a clean weld). </p><p>Step 2 is to TIG weld inside and outside of the alloy wheel. Once the weld is complete it is as strong as a new wheel. </p><p>Finally we will dress the weld back on the inside of the wheel which allows the tyre to re-seal correctly.<br /></p>\n\n<p>We also offer Alloy wheel straightening. We mount the wheel onto our straightening machine and heat the affected area using a small propane torch (this stops the wheel cracking). Hydraulic cylinders are used to press the wheel back into shape. The wheel is then spun and checked for straightness using a dial test indicator.</p>\n<p>Get in touch for all your alloy wheel repair / straightening requirements on 01274 744887</p>'),(9,957,2,'2020-06-10 13:43:15','2020-06-10 13:43:15','c312a150-b6df-412c-8d6c-762e061669a9',NULL,'<h1>Alloy Wheel Repair</h1>\n<p>Cracked alloy wheels are becoming an increasingly common problem due to poor road conditions. Often the cracks are discovered when a slow puncture occurs.</p>\n<p>We offer alloy wheel repairs across West Yorkshire. Cracks can be repaired and you can still keep the wheels strength and integrity.</p>\n<p>We will check the alloy wheel for cracks, stress fractures or kerb damage. The first step of the repair process is to grind both sides of the crack (to remove any contamination therefore giving a clean weld). Step 2 is to TIG weld inside and out of the alloy wheel – once the weld is complete it is as strong as a new wheel. Finally we will dress the weld back on the inside of the wheel which allows the tyre to re-seal correctly.</p>\n<p>Straightening alloy wheels Yorkshire</p>\n<p>We also offer Alloy wheel straightening. First we mount the wheel onto our straightening machine and heat the affected area using a small propane torch (this stops the wheel cracking). Hydraulic cylinders are used to press the wheel back into shape. The wheel is then spun and checked for straightness using a dial test indicator.</p>\n<p>Get in touch for all your alloy wheel repair / straightening requirements on 01274 744887</p>'),(11,960,2,'2020-06-10 13:44:26','2020-06-10 13:44:26','0a315743-8757-4f5e-8d1a-90531bf9a297',NULL,'<p>Cracked alloy wheels are becoming an increasingly common problem due to poor road conditions. Often the cracks are discovered when a slow puncture occurs.<br /></p>\n<p>We offer alloy wheel repairs across West Yorkshire. Cracks can be repaired and you can still keep the wheels strength and integrity.</p>\n<p>We will check the alloy wheel for cracks, stress fractures or kerb damage. The first step of the repair process is to grind both sides of the crack (to remove any contamination therefore giving a clean weld). Step 2 is to TIG weld inside and out of the alloy wheel – once the weld is complete it is as strong as a new wheel. Finally we will dress the weld back on the inside of the wheel which allows the tyre to re-seal correctly.</p>\n<p>Straightening alloy wheels Yorkshire</p>\n<p>We also offer Alloy wheel straightening. First we mount the wheel onto our straightening machine and heat the affected area using a small propane torch (this stops the wheel cracking). Hydraulic cylinders are used to press the wheel back into shape. The wheel is then spun and checked for straightness using a dial test indicator.</p>\n<p>Get in touch for all your alloy wheel repair / straightening requirements on 01274 744887</p>'),(13,1310,2,'2020-07-14 15:18:08','2020-07-14 15:18:08','6b3c652c-7915-43b7-b9ff-1a8391c453a0',NULL,'<p>Cracked alloy wheels are becoming an increasingly common problem due to poor road conditions. </p><p>We can repair cracks, stress fractures or kerb damage whilst maintaining the wheel strength and integrity.</p>\n\n<p>The first step of the repair process is to grind both sides of the crack (to remove any contamination therefore giving a clean weld). </p><p>Step 2 is to TIG weld inside and outside of the alloy wheel. Once the weld is complete it is as strong as a new wheel. </p><p>Finally we will dress the weld back on the inside of the wheel which allows the tyre to re-seal correctly.<br /></p>\n\n<p>We also offer Alloy wheel straightening. We mount the wheel onto our straightening machine and heat the affected area using a small propane torch (this stops the wheel cracking). Hydraulic cylinders are used to press the wheel back into shape. The wheel is then spun and checked for straightness using a dial test indicator.</p>\n<p>Get in touch for all your alloy wheel repair / straightening requirements on 01274 744887</p>'),(18,1877,2,'2024-01-29 15:59:21','2024-01-29 15:59:21','63b2db77-cdb5-4f2e-9f1b-5c3f01ba81ac',NULL,'<p>Cracked alloy wheels are becoming an increasingly common problem due to poor road conditions. </p><p>We can repair cracks, stress fractures or kerb damage whilst maintaining the wheel strength and integrity.</p>\n\n<p>The first step of the repair process is to grind both sides of the crack (to remove any contamination therefore giving a clean weld). </p><p>Step 2 is to TIG weld inside and outside of the alloy wheel. Once the weld is complete it is as strong as a new wheel. </p><p>Finally we will dress the weld back on the inside of the wheel which allows the tyre to re-seal correctly.<br /></p>\n\n<p>We also offer Alloy wheel straightening. We mount the wheel onto our straightening machine and heat the affected area using a small propane torch (this stops the wheel cracking). Hydraulic cylinders are used to press the wheel back into shape. The wheel is then spun and checked for straightness using a dial test indicator.</p>\n<p>Get in touch for all your alloy wheel repair / straightening requirements on 01274 744887</p>'),(21,1918,2,'2025-10-06 07:28:38','2025-10-06 07:28:38','6abb683c-57a7-4932-ad59-67b4751b40b5','TRANSMISSIONS',NULL);
